Here's how to test `DataFetcher` with MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static HttpClient CreateMockClient(HttpMessageHandler handler) => new(handler);

    // --- Success path ---
    [TestMethod]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        var fetcher = new DataFetcher(CreateMockClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello world", result);
    }

    // --- Error status code ---
    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.InternalServerError,
        });
        var fetcher = new DataFetcher(CreateMockClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation ---
    [TestMethod]
    public async Task FetchAsync_WhenCancelled_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new FakeHandler(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        var fetcher = new DataFetcher(CreateMockClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via [Timeout] + TestContext.CancellationToken ---
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_SlowServer_RespectsCancellationToken()
    {
        // Handler that delays indefinitely — the [Timeout] will cancel via TestContext
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(CreateMockClient(handler));

        // Pass TestContext.CancellationToken so the [Timeout] can cancel the call
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Fake handler ---
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage response)
            : this((_, _) => Task.FromResult(response)) { }

        public FakeHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key takeaways:**

| Pattern | Why |
|---|---|
| `sealed class` | Performance + design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, satisfies nullability |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]` — lets you assert the exact type |
| `TestContext.CancellationToken` | Cooperates with `[Timeout]` — the framework cancels the token when time expires |
| `FakeHandler` over mocking `HttpClient` | `HttpClient` can't be mocked directly; substitute the `HttpMessageHandler` instead |

The critical detail: always pass `TestContext.CancellationToken` through to async calls in tests with `[Timeout]`. Without it, the timeout kills the test thread but the HTTP call keeps running.
